t.script:
document.addEventListener('DOMContentLoaded', function () {
    // Handle View Images button click
    document.querySelectorAll('.view-task-images-btn').forEach(function(btn) {
        btn.addEventListener('click', function() {
            var row = this.closest('tr');
            var imagesDataStr = row.getAttribute('data-images');

            // Parse images data from data attribute
            var images = [];
            try {
                if (imagesDataStr) {
                    var parsed = JSON.parse(imagesDataStr.replace(/'/g, '"'));
                    if (Array.isArray(parsed)) {
                        parsed.forEach(function(img) {
                            images.push({
                                src: 'data:' + (img.mimetype || 'image/jpeg') + ';base64,' + (img.image || ''),
                                mimetype: img.mimetype || 'image/jpeg'
                            });
                        });
                    }
                }
            } catch(e) {
                console.error('Error parsing images data:', e);
                // Fallback: get images from visible thumbnails
                var imageElements = row.querySelectorAll('img.o_portal_contact_img');
                imageElements.forEach(function(img) {
                    images.push({
                        src: img.src,
                        mimetype: img.src.split(';')[0].split(':')[1] || 'image/jpeg'
                    });
                });
            }

            // Clear previous images
            var container = document.getElementById('taskImagesContainer');
            container.innerHTML = '';

            if (images.length === 0) {
                container.innerHTML = '<div class="col-12 text-center text-muted"><p>No images available for this task.</p></div>';
            } else {
                images.forEach(function(img) {
                    var colDiv = document.createElement('div');
                    colDiv.className = 'col-md-6 col-lg-4 mb-3';

                    var imgElement = document.createElement('img');
                    imgElement.src = img.src;
                    imgElement.className = 'img-fluid rounded';
                    imgElement.style.cursor = 'pointer';
                    imgElement.style.width = '100%';
                    imgElement.style.height = '250px';
                    imgElement.style.objectFit = 'cover';
                    imgElement.style.objectPosition = 'center';
                    imgElement.title = 'Click to view full size';

                    // Handle image load error
                    imgElement.onerror = function() {
                        console.error('Failed to load image');
                        this.style.display = 'none';
                    };

                    // Make image clickable to view full size
                    imgElement.addEventListener('click', function() {
                        var fullSizeModalEl = document.getElementById('taskFullSizeImageModal');
                        if (!fullSizeModalEl) {
                            fullSizeModalEl = createTaskFullSizeModal();
                        }
                        var fullSizeImg = document.getElementById('taskFullSizeImage');
                        if (fullSizeImg) {
                            fullSizeImg.src = this.src;
                            if (typeof $ !== 'undefined') {
                                $(fullSizeModalEl).modal('show');
                            } else {
                                fullSizeModalEl.classList.add('show');
                                fullSizeModalEl.style.display = 'block';
                                fullSizeModalEl.setAttribute('aria-hidden', 'false');
                                document.body.classList.add('modal-open');
                            }
                        }
                    });

                    colDiv.appendChild(imgElement);
                    container.appendChild(colDiv);
                });
            }

            // Show modal using jQuery or manual method
            var modalEl = document.getElementById('taskImagesModal');
            if (typeof $ !== 'undefined') {
                $(modalEl).modal('show');
            } else {
                modalEl.classList.add('show');
                modalEl.style.display = 'block';
                modalEl.setAttribute('aria-hidden', 'false');
                document.body.classList.add('modal-open');
                var existingBackdrop = document.getElementById('taskModalBackdrop');
                if (existingBackdrop) {
                    existingBackdrop.remove();
                }
                var backdrop = document.createElement('div');
                backdrop.className = 'modal-backdrop fade show';
                backdrop.id = 'taskModalBackdrop';
                document.body.appendChild(backdrop);
            }
        });
    });

    // Handle modal close buttons
    function closeTaskModal(modalEl) {
        if (typeof $ !== 'undefined') {
            $(modalEl).modal('hide');
        } else {
            modalEl.classList.remove('show');
            modalEl.style.display = 'none';
            modalEl.setAttribute('aria-hidden', 'true');
            document.body.classList.remove('modal-open');
            var backdrop = document.getElementById('taskModalBackdrop');
            if (backdrop) {
                backdrop.remove();
            }
        }
    }

    // Add close handlers to modal buttons
    document.addEventListener('click', function(e) {
        if (e.target.classList.contains('close-task-modal-btn')) {
            var modal = e.target.closest('.modal');
            if (modal) {
                closeTaskModal(modal);
            }
        }
    });

    // Close modal when clicking backdrop
    var taskImagesModalEl = document.getElementById('taskImagesModal');
    if (taskImagesModalEl) {
        taskImagesModalEl.addEventListener('click', function(e) {
            if (e.target === this) {
                closeTaskModal(this);
            }
        });
    }

    // Create full size image modal if it doesn't exist
    function createTaskFullSizeModal() {
        var modalDiv = document.createElement('div');
        modalDiv.className = 'modal fade';
        modalDiv.id = 'taskFullSizeImageModal';
        modalDiv.innerHTML = '<div class="modal-dialog modal-fullscreen"><div class="modal-content bg-dark"><div class="modal-header border-0"><button type="button" class="btn-close btn-close-white close-task-fullsize-modal" aria-label="Close"></button></div><div class="modal-body d-flex align-items-center justify-content-center p-0"><img id="taskFullSizeImage" class="img-fluid" style="max-height: 100vh; max-width: 100%; object-fit: contain;" /></div></div></div>';
        document.body.appendChild(modalDiv);

        // Add close handler for full size modal
        modalDiv.querySelector('.close-task-fullsize-modal').addEventListener('click', function() {
            closeTaskModal(modalDiv);
        });

        // Close on backdrop click
        modalDiv.addEventListener('click', function(e) {
            if (e.target === modalDiv) {
                closeTaskModal(modalDiv);
            }
        });

        return modalDiv;
    }
});
